use std::ops::{Add, Mul, Sub};
use std::fmt;

#[derive(Debug, Clone, Copy)]
struct SimdVec<T, const N: usize> {
    lanes: [T; N],
}

impl<T: Copy, const N: usize> SimdVec<T, N> {
    pub fn new(lanes: [T; N]) -> Self { SimdVec { lanes } }
    pub fn splat(val: T) -> Self { SimdVec { lanes: [val; N] } }
    pub fn lane(&self, i: usize) -> T { self.lanes[i] }
}

macro_rules! impl_binop {
    ($trait:ident, $method:ident, $op:tt) => {
        impl<T: Copy + $trait<Output = T>, const N: usize> $trait for SimdVec<T, N> {
            type Output = SimdVec<T, N>;
            fn $method(self, rhs: SimdVec<T, N>) -> SimdVec<T, N> {
                let mut r = self.lanes;
                for i in 0..N { r[i] = self.lanes[i] $op rhs.lanes[i]; }
                SimdVec { lanes: r }
            }
        }
    }
}

impl_binop!(Add, add, +);
impl_binop!(Sub, sub, -);
impl_binop!(Mul, mul, *);

impl<T: Copy + Add<Output = T>, const N: usize> SimdVec<T, N> {
    pub fn horizontal_sum(self) -> T where T: Default {
        self.lanes.iter().copied().fold(T::default(), |a, b| a + b)
    }
}

