    pub fn push(&mut self, val: T) -> bool {
        if self.len() == CAP { return false; } // full
        // CAP - 1 is a compile-time constant — LLVM uses lea/and, no idiv
        self.data[self.tail & (CAP - 1)] = val;
        self.tail += 1;
