        if self.is_empty() { return None; }
        let val = self.data[self.head & (CAP - 1)];
        self.head += 1;
        Some(val)
    }

    pub fn len(&self) -> usize { self.tail - self.head }
    pub fn is_empty(&self) -> bool { self.tail == self.head }
    pub fn capacity(&self) -> usize { CAP }
}

