const fn make_identity<const N: usize>() -> [usize; N] {
    let mut table = [0usize; N];
    let mut i = 0;
    while i < N { table[i] = i; i += 1; }
    table
}

const fn make_squares<const N: usize>() -> [u64; N] {
    let mut table = [0u64; N];
    let mut i = 0;
    while i < N { table[i] = (i * i) as u64; i += 1; }
    table
}

// CRC table — a real use case for compile-time tables:
const fn make_crc32_table() -> [u32; 256] {
    let mut table = [0u32; 256];
    let mut i = 0usize;
    while i < 256 {
        let mut c = i as u32;
        let mut j = 0;
        while j < 8 {
            if c & 1 != 0 { c = 0xEDB88320 ^ (c >> 1); }
            else          { c >>= 1; }
            j += 1;
        }
        table[i] = c;
        i += 1;
    }
    table
}

