// Meanwhile, runtime const-generic counter (no expression needed):
struct Counter<const START: usize> {
    current: usize,
}

impl<const START: usize> Counter<START> {
    pub fn new() -> Self { Counter { current: START } }
    pub fn next(&mut self) -> usize { let v = self.current; self.current += 1; v }
    pub const START: usize = START;
}

